  \label{lem:degree_positivePart_principal_eq_finrank}
  \lean{AlgebraicGeometry.Scheme.WeilDivisor.degree_positivePart_principal_eq_finrank}
  \uses{def:WeilDivisor_positivePart, def:principal_divisor,
        def:order_at_point, def:divisor_degree, def:prime_divisor,
        lem:degree_positivePart_eq_sum_max,
        lem:finsupp_sum_max_zero_eq_sum_filter_pos,
        lem:one_le_degree_positivePart_principal_of_order_one,
        lem:principal_apply, lem:order_pow_of_ne_zero,
        lem:degree_single, lem:positivePart_single,
        def:projectiveLineBar_isLocallyNoetherian,
        thm:projectiveLineBar_isRegularInCodimOne}
  % SOURCE: [Hartshorne], II.6, Proposition~6.9, p.~137 (multiplicativity
  % of degree under finite pullback) (read from
  % references/hartshorne-algebraic-geometry.pdf, PDF page 154).
  % Stacks pointer: tag 02RW (pullback of divisors under finite
  % morphisms), tag 0BE6 (degree under finite morphism).
  % SOURCE QUOTE: "Proposition 6.9. \emph{Let \(f \colon X \to Y\) be a finite
  % morphism of nonsingular curves. Then for any divisor \(D\) on \(Y\),
  % \(\deg(f^\ast D) = [K(X) : K(Y)] \cdot \deg D\).}"
  \textit{Source: Hartshorne, II.6, Proposition~6.9, p.~137.}
  Let \(C\) be a smooth proper geometrically irreducible curve over an
  algebraically closed field \(\bar k\), and let
  \(\varphi \colon C \to \mathbb P^1_{\bar k}\) be a non-constant morphism.
  Let \(t_\infty \in K(\mathbb P^1)\) be a local parameter at \(\infty \in \mathbb P^1\)
  (equivalently \(t_\infty = 1/u\) for the standard affine coordinate \(u\) on
  \(\mathbb P^1 \setminus \{\infty\}\)). Write \(f := \varphi^{\#} t_\infty
  \in K(C)\) for the pullback of \(t_\infty\) along \(\varphi\). Then \(f\) is
  nonzero (because \(\varphi\) is non-constant; equivalently \(\varphi^{-1}(\infty)\)
  is a proper closed subscheme of \(C\)) and the degree of the positive
  part of the principal divisor of \(f\) equals the function-field
  extension degree:
  \[
    \deg\bigl((\mathrm{div}(f))_0\bigr)
    \;=\; \bigl[\,K(C) \,:\, \bar k(\mathbb P^1)\,\bigr]
    \;=\; \mathrm{Module.finrank}_{\bar k(\mathbb P^1)} K(C).
  \]
  Equivalently, \((\mathrm{div}(f))_0 = \varphi^{*}[\infty]\) (the effective
  preimage divisor of \(\infty\)) and \(\deg(\varphi^{*}[\infty]) = \deg(\varphi)\).
\end{lemma}
% SOURCE QUOTE PROOF: "PROOF. The morphism \(f \colon X \to Y\) is finite,
% so locally on \(Y\) corresponds to a finite extension of Dedekind domains
% \(A \subset B\). For each closed point \(P \in Y\) the ramification--inertia
% formula gives \(\sum_{Q | P} e_Q f_Q = [K(X) : K(Y)]\), where the sum runs
% over closed points \(Q \in X\) above \(P\). Summing this identity over
% \(P \in Y\) using the affine cover and noting that \(D = \sum_P n_P [P]\)
% gives \(\deg(f^\ast D) = \sum_{P} n_P \sum_{Q | P} e_Q f_Q
% = \sum_P n_P [K(X) : K(Y)] = [K(X) : K(Y)] \deg(D)\)."
\begin{proof}
  Following Hartshorne's Proposition~II.6.9 specialised to the divisor
  \(D = [\infty]\) on \(\mathbb P^1_{\bar k}\). A non-constant morphism
  between smooth proper curves over \(\bar k\) is automatically finite (the
  image is a closed irreducible subset that is not a point and not empty,
  hence all of \(\mathbb P^1\); a surjective morphism between smooth proper
  irreducible curves of equal dimension is proper + quasi-finite, hence
  finite; cf.\ Hartshorne II.6.8). Hence the function-field extension
  \(\bar k(\mathbb P^1) \hookrightarrow K(C)\) is finite of degree
  \(d := [K(C) : \bar k(\mathbb P^1)] = \dim_{\bar k(\mathbb P^1)} K(C)\).
  Pick an affine open \(\mathrm{Spec}(A) \subset \mathbb P^1_{\bar k}\) containing
  \(\infty\); explicitly take \(A = \bar k[t_\infty]\) the standard chart at
  \(\infty\), with \(\infty\) corresponding to the maximal ideal
  \(\mathfrak m_\infty = (t_\infty) \subset A\). The preimage
  \(\mathrm{Spec}(B) := \varphi^{-1}(\mathrm{Spec}(A))\) is an affine open of \(C\)
  with \(B\) a finite (and integrally closed, by \(C\) smooth) extension of
  \(A\); both are Dedekind domains. Apply
  \texttt{Ideal.sum\_ramification\_inertia} (Mathlib,
  \texttt{Mathlib.NumberTheory.RamificationInertia.Basic}) to the
  ring-theoretic extension \(A \to B\) at the maximal ideal
  \(\mathfrak m_\infty\):
  \[
    \sum_{Q \,\colon\, \mathfrak m_\infty \subset Q} e_{Q | \mathfrak m_\infty} \cdot f_{Q | \mathfrak m_\infty}
    \;=\; \dim_{A / \mathfrak m_\infty}\!\bigl(B / \mathfrak m_\infty B\bigr)
    \;=\; \dim_{\bar k(\mathbb P^1)} K(C) \;=\; d,
  \]
  where the second equality uses
  \texttt{Ideal.finrank\_quotient\_map} (which identifies the residue-field
  quotient with the function-field extension degree for a Dedekind extension
  at a maximal ideal). The closed points \(Q \subset \mathrm{Spec}(B)\) above
  \(\mathfrak m_\infty\) are precisely the closed points
  \(P \in \varphi^{-1}(\infty) \subset C\); the ramification index
  \(e_{Q | \mathfrak m_\infty}\) is the order \(\ord_P(\varphi^{\#} t_\infty)\)
  of the pulled-back local parameter at \(P\); the residue degree
  \(f_{Q | \mathfrak m_\infty}\) is \([\kappa(P) : \bar k] = 1\) (every closed
  point of \(C\) over \(\bar k\) has residue field \(\bar k\)). Therefore
  \[
    \sum_{P \,\in\, \varphi^{-1}(\infty)} \ord_P(\varphi^{\#} t_\infty) \;=\; d
    \;=\; \mathrm{Module.finrank}_{\bar k(\mathbb P^1)} K(C).
  \]
  The left-hand side equals the degree of the positive part of
  \(\mathrm{div}(\varphi^{\#} t_\infty)\), because: at every closed point
  \(P \in \varphi^{-1}(\infty)\) the order is \(\geq 1\) (pullback of a local
  parameter under a finite morphism is itself a uniformiser-power, hence
  has positive order at every preimage); at every closed point
  \(P \in C \setminus \varphi^{-1}(\infty)\) the rational function
  \(\varphi^{\#} t_\infty\) is regular and nonzero (because \(t_\infty\) is
  regular and nonzero on \(\mathbb P^1 \setminus \{\infty\}\)), hence the
  order at such a \(P\) is \(\geq 0\); the points where the order is
  \emph{strictly} positive are exactly the points of \(\varphi^{-1}(\infty)\).
  Therefore
  \(\,(\mathrm{div}(\varphi^{\#} t_\infty))_0 = \sum_{P \in \varphi^{-1}(\infty)}
  \ord_P(\varphi^{\#} t_\infty) \cdot [P] = \varphi^{*}[\infty]\,\), and
  taking degree completes the proof.
\end{proof}
\section{Divisor class group}
We follow Hartshorne II.6 (pp.~131--132) and define the divisor class group
of a curve as the cokernel of the principal-divisor homomorphism. This is
the \emph{Picard group} of \(C\) in the curve-specific sense; the line-bundle
interpretation \(\Cl(C) \cong \Pic(C)\) requires the construction of
\(\mathcal O_C(D)\), which lives in the sibling chapter \texttt{RR.3} and is
out of scope here.
\begin{definition}
\leanok
[Linear equivalence of divisors]
  \label{def:linear_equivalence}
  \lean{AlgebraicGeometry.Scheme.WeilDivisor.LinearEquivalence}
  \uses{def:principal_divisor, thm:principal_hom, def:codim1_cycles}
  % SOURCE: [Hartshorne], II.6, p.~131 (definition of linear equivalence
  % and of \(\operatorname{Cl} X\)) (read from
  % references/hartshorne-algebraic-geometry.pdf, PDF page 148).
  % SOURCE QUOTE: "Definition. Let \(X\) satisfy \((\ast)\). Two divisors \(D\)
  % and \(D'\) are said to be \emph{linearly equivalent}, written \(D \sim D'\),
  % if \(D - D'\) is a principal divisor. The group \(\operatorname{Div} X\) of
  % all divisors divided by the subgroup of principal divisors is called
  % the \emph{divisor class group} of \(X\), and is denoted by
  % \(\operatorname{Cl} X\)."
  \textit{Source: Hartshorne, II.6, p.~131 (linear equivalence and
  \(\operatorname{Cl} X\)).}
  Let \(X\) satisfy \((*)\). Two Weil divisors \(D, D' \in \mathrm{Div}(X)\) are
  \emph{linearly equivalent}, written \(D \sim D'\), if and only if there
  exists \(f \in K(X)^{\times}\) with
  \[
    D - D' \;=\; \mathrm{div}(f) \;\in\; \mathrm{Div}(X).
  \]
  The relation \(\sim\) is an equivalence relation on \(\mathrm{Div}(X)\) (the
  reflexivity, symmetry, and transitivity all transport from the analogous
  identities \(\mathrm{div}(1) = 0\), \(\mathrm{div}(f^{-1}) = -\mathrm{div}(f)\), $\mathrm{div}(fg) =
  \mathrm{div}(f) + \mathrm{div}(g)$ via \ref{thm:principal_hom}); the corresponding
  quotient group \(\Cl(X) := \mathrm{Div}(X) / \mathrm{im}(\div)\) is the
  \emph{divisor class group} of \(X\). On a smooth proper curve \(C\) over
  \(\bar k\), \ref{thm:principal_deg_zero} implies that the degree map
  \(\deg \colon \mathrm{Div}(C) \to \mathbb Z\) descends to a homomorphism
  \(\deg \colon \Cl(C) \to \mathbb Z\).
\end{definition}
\section{Out of scope}
The following items are deliberately \emph{not} part of \texttt{RR.1} and
are sequenced into the sibling sub-build chapters:
\begin{itemize}
  \item The line-bundle construction \(\mathcal O_C(D)\) associated to a Weil
    divisor \(D\), the calculation of its global sections, and the
    identification \(\mathcal O_C(D) \cong \mathcal O_C(D')\) when
    \(D \sim D'\), lives in \texttt{RR.3} (sibling chapter
    \texttt{RiemannRoch\_OcOfD.tex}, to be added).
  \item The Riemann--Roch dimension formula
    \(\ell(D) - \ell(K - D) = \deg(D) + 1 - g\) and its genus-\(0\) specialisation
    \(\ell(D) = \deg(D) + 1\) for \(\deg(D) \geq 0\) live in \texttt{RR.2}
    (sibling chapter \texttt{RiemannRoch\_RRFormula.tex}, to be added).
  \item The classification ``a smooth proper geometrically irreducible
    curve over \(\bar k\) with \(g = 0\) is isomorphic to \(\mathbb P^1\)''
    (Hartshorne Example~IV.1.3.5) is the headline of \texttt{RR.4}
    (sibling chapter \texttt{RiemannRoch\_RationalIsoP1.tex}, to be added)
    and assembles \texttt{RR.1}/\texttt{RR.2}/\texttt{RR.3} into the
    \texttt{Proj.fromOfGlobalSections} morphism into \(\mathbb P^1\) together
    with its degree-\(1\) identification.
  \item \emph{Cartier divisors} (locally principal divisors on a possibly
    singular scheme) are out of scope: the project's curves are smooth, so
    Weil and Cartier divisors coincide, and the simpler Weil form suffices.
    A future Mathlib upstream PR could introduce the Cartier formalism.
  \item \emph{Higher-codimension cycles} (the Chow group
    \(\bigoplus_i \mathrm{CH}^i(X)\)) are out of scope: this chapter is
    strictly curve-focused.
  \item The proof of \ref{thm:principal_deg_zero} factors through two
    auxiliary statements (``finite morphism induced by a non-constant
    rational function'' and ``multiplicativity of degree under finite
    pullback'', Hartshorne II.6.9) which are themselves separable
    sub-lemmas of \texttt{RR.1}; they are flagged in the proof body but
    deliberately not unfolded as standalone declarations here.
\end{itemize}

\chapter{Codimension-one points are \texorpdfstring{$\bar k$}{kbar}-rational}
\label{chap:RiemannRoch_ResidueFieldKbar}

% archon:covers AlgebraicJacobian/RiemannRoch/ResidueFieldKbar.lean

% Chapter-local fallbacks for the order-theoretic dimension macros (not yet in
% blueprint/src/macros/common.tex).  See the writer report "needs macros" note.
\providecommand{\Order}{\mathrm{Order}}
\providecommand{\krullDim}{\dim}
\providecommand{\coheight}{\operatorname{coheight}}
\providecommand{\height}{\operatorname{ht}}

This chapter collects the project-local commutative-algebra and topological
substrate behind the codimension-one rationality statement
\cref{lem:codimOne_point_residueField_eq_kbar}, proved at the end of this
chapter and consumed by the regularity substrate of
\cref{chap:RiemannRoch_OcOfD}.  At a closed point of an integral finite-type
curve over an algebraically closed field $\bar k$ the residue field is $\bar k$
itself; the file isolates the two ingredients --- the affine-local residue-field
computation (Zariski/Nullstellensatz plus algebraic-closure triviality) and the
topological ``coheight one $\Rightarrow$ closed point'' implication --- as
standalone supplementary lemmas, then glues them into the scheme-level statement.

\begin{lemma}[Finite-type field extension of $\bar k$ is trivial]
  \label{lem:algebraMap_bijective_of_finiteType}
  \lean{IsAlgClosed.algebraMap_bijective_of_finiteType}
  \leanok
  Let $\bar k$ be algebraically closed and $K$ a field that is a finite-type
  $\bar k$-algebra.  Then the structure map $\bar k \to K$ is bijective.
\end{lemma}

\begin{proof}\leanok
  By Zariski's lemma (the Nullstellensatz in Jacobson-ring form), $K$ is
  module-finite, hence integral, over $\bar k$.  An integral extension of
  an algebraically closed field is trivial, so the structure map is bijective.
\end{proof}

\begin{lemma}[Residue field at a maximal ideal of a finite-type $\bar k$-algebra]
  \label{lem:algebraMap_residueField_bijective_of_isMaximal}
  \lean{IsAlgClosed.algebraMap_residueField_bijective_of_isMaximal}
  \leanok
  \uses{lem:algebraMap_bijective_of_finiteType}
  Let $\bar k$ be algebraically closed and $A$ a finite-type $\bar k$-algebra.
  For a maximal ideal $\mathfrak p$ of $A$, the structure map
  $\bar k \to \kappa(\mathfrak p)$ into the residue field is bijective.
\end{lemma}

\begin{proof}\leanok
  The residue field $\kappa(\mathfrak{p}) = A/\mathfrak{p}$ is a surjective
  quotient of $A$, hence itself a finite-type $\bar k$-algebra; the conclusion
  follows from \cref{lem:algebraMap_bijective_of_finiteType}.
\end{proof}

The downstream conormal comparison reads the residue rationality not as a bare
bijection but through three formal vanishing facts ($\Omega_{K/\bar k} = 0$,
$H^1_{\mathrm{cot}}(\bar k, K) = 0$, and formal smoothness), all of which follow
once the structure map $\bar k \to K$ is bijective --- i.e.\ once $K \cong \bar k$
as a $\bar k$-algebra.  The next four blocks package exactly this interface,
keyed on bijectivity of the structure map so that the geometric application can
feed them $K = \kappa(x)$.

\begin{definition}\leanok
[$\bar k$-algebra isomorphism from a bijective structure map]
  \label{def:algEquivOfAlgebraMapBijective}
  \lean{algEquivOfAlgebraMapBijective}
  For fields $\bar k, K$ with the $\bar k$-algebra structure map $\bar k \to K$
  bijective, that map packages canonically as a $\bar k$-algebra isomorphism
  $\bar k \cong K$.
\end{definition}

\begin{lemma}\leanok
[Bijective structure map gives formal smoothness]
  \label{lem:formallySmooth_of_algebraMap_bijective}
  \lean{formallySmooth_of_algebraMap_bijective}
  \uses{def:algEquivOfAlgebraMapBijective}
  If the structure map $\bar k \to K$ is bijective, then $K$ is formally smooth
  over $\bar k$.
\end{lemma}

\begin{proof}
  \uses{def:algEquivOfAlgebraMapBijective}
  \leanok
  By \cref{def:algEquivOfAlgebraMapBijective} the structure map is a
  $\bar k$-algebra isomorphism $K \cong \bar k$.  Formal smoothness is invariant
  under algebra isomorphism, and $\bar k$ is formally smooth over itself.
\end{proof}

\begin{lemma}\leanok
[Bijective structure map kills Kähler differentials]
  \label{lem:subsingleton_kaehlerDifferential_of_algebraMap_bijective}
  \lean{subsingleton_kaehlerDifferential_of_algebraMap_bijective}
  \uses{def:algEquivOfAlgebraMapBijective}
  If the structure map $\bar k \to K$ is bijective, then $\Omega_{K/\bar k} = 0$.
\end{lemma}

\begin{proof}
  \uses{def:algEquivOfAlgebraMapBijective}
  \leanok
  Through the isomorphism $K \cong \bar k$ of
  \cref{def:algEquivOfAlgebraMapBijective}, $K$ is formally unramified over
  $\bar k$, and the module of Kähler differentials of a formally unramified
  algebra vanishes.
\end{proof}

\begin{lemma}\leanok
[Bijective structure map kills $H^1$ of the cotangent complex]
  \label{lem:subsingleton_h1Cotangent_of_algebraMap_bijective}
  \lean{subsingleton_h1Cotangent_of_algebraMap_bijective}
  \uses{lem:formallySmooth_of_algebraMap_bijective}
  If the structure map $\bar k \to K$ is bijective, then the first cotangent
  cohomology $H^1_{\mathrm{cot}}(\bar k, K)$ vanishes.
\end{lemma}

\begin{proof}
  \uses{lem:formallySmooth_of_algebraMap_bijective}
  \leanok
  $K$ is formally smooth over $\bar k$
  (\cref{lem:formallySmooth_of_algebraMap_bijective}), and the first cotangent
  cohomology of a formally smooth algebra vanishes.
\end{proof}

\section{Coheight one is closed, and the scheme-level statement}

\begin{lemma}[Coheight-one points of a dimension-$\le 1$ scheme are closed]
  \label{lem:isClosed_singleton_of_coheight_eq_one}
  \lean{AlgebraicGeometry.isClosed_singleton_of_coheight_eq_one}
  \leanok
  Let $X$ be a scheme whose underlying space has Krull dimension at most one (in
  the specialisation order).  If $x \in X$ has $\coheight(x) = 1$ then
  $\{x\}$ is closed.
\end{lemma}

\begin{proof}\leanok
  From $\krullDim X = \sup_a (\height a + \coheight a)$ and $\coheight x = 1$,
  $\dim X \le 1$ forces $\height x = 0$, i.e.\ $x$ is minimal in the
  specialisation order.  A specialisation-minimal point of a $T_0$ space is
  closed (its closure, the set of its specialisations, reduces to $\{x\}$).
\end{proof}

\begin{definition}\leanok
[$\bar k$-algebra on a residue field from the structure morphism]
  \label{def:residueFieldAlgebra}
  \lean{AlgebraicGeometry.residueFieldAlgebra}
  For a scheme $C$ over $\operatorname{Spec}\bar k$ and a point $x \in C$, the
  structure morphism $C \to \operatorname{Spec}\bar k$ induces a canonical
  $\bar k$-algebra structure on the residue field $\kappa(x)$ (via the residue-field
  map of the morphism at $x$ and the identification $\kappa(\ast)=\bar k$ at the
  base point).  This $\bar k$-algebra structure is not canonical from $\kappa(x)$
  alone but requires the data of the structure morphism, so it is recorded
  explicitly to state $\bar k$-rationality below.
\end{definition}

\begin{lemma}[Residue field of a closed point over an algebraically closed base]
  \label{lem:residueFieldIsoBase_mathlib}
  \lean{AlgebraicGeometry.residueFieldIsoBase}
  \mathlibok
  \textit{Provided by Mathlib.}
  Let $f : X \to \operatorname{Spec}\bar k$ be a morphism locally of finite type to
  the spectrum of an algebraically closed field $\bar k$, and let $x \in X$ be a
  point whose singleton $\{x\}$ is closed.  Then the residue field $\kappa(x)$ is
  canonically isomorphic, as a $\bar k$-algebra, to $\bar k$ itself.
\end{lemma}

\begin{lemma}\leanok
[Codimension-one points are $\bar k$-rational]
  \label{lem:codimOne_point_residueField_eq_kbar}
  \lean{AlgebraicGeometry.residueField_eq_of_coheight_eq_one}
  \uses{lem:isClosed_singleton_of_coheight_eq_one,
        lem:residueFieldIsoBase_mathlib,
        def:residueFieldAlgebra}
  Let $C$ be an integral curve of finite type over an algebraically closed field
  $\bar k$, and let $x \in C$ be a point with $\coheight x = 1$.  Then $x$ is a
  closed point and the canonical map $\bar k \to \kappa(x)$ is an isomorphism; in
  particular $\kappa(x) = \bar k$.
\end{lemma}

\begin{proof}
  \uses{lem:isClosed_singleton_of_coheight_eq_one,
        lem:residueFieldIsoBase_mathlib,
        def:residueFieldAlgebra}
        \leanok
  The closedness step \cref{lem:isClosed_singleton_of_coheight_eq_one} requires
  the topological dimension bound $\krullDim C \le 1$ as an explicit input,
  which the statement carries as the hypothesis $\krullDim C \le 1$.
  Granting this bound, \cref{lem:isClosed_singleton_of_coheight_eq_one} applies to
  the coheight-one point $x$ and shows that $\{x\}$ is closed; this is the first
  conclusion.

  For the residue-field rationality, the structure morphism $C \to
  \operatorname{Spec}\bar k$ is locally of finite type and $\bar k$ is
  algebraically closed, so \cref{lem:residueFieldIsoBase_mathlib} applies to the
  closed point $x$ and supplies a canonical isomorphism
  $\rho \colon \kappa(x) \cong \bar k$.  Its inverse
  $\rho^{-1} \colon \bar k \cong \kappa(x)$ is an isomorphism of rings, hence
  bijective.

  It remains to identify the canonical structure map $\bar k \to \kappa(x)$ of
  \cref{def:residueFieldAlgebra} with $\rho^{-1}$, after which bijectivity is
  immediate.  By construction the structure map is the composite of the
  residue-field map of the structure morphism at $x$ with the base identification
  $\kappa(\ast) = \bar k$.  This composite and $\rho^{-1}$ agree because they agree
  after applying the (fully faithful) spectrum functor $\operatorname{Spec}(-)$:
  there both sides reduce to the canonical morphism
  $\operatorname{Spec}\kappa(x) \to C$ from the spectrum of the residue field,
  using the compatibility of $\rho^{-1}$ with this canonical morphism and the
  compatibility of the residue-field map of the structure morphism with it.  Since
  $\operatorname{Spec}(-)$ is faithful, the two maps are equal; hence the structure
  map $\bar k \to \kappa(x)$ equals $\rho^{-1}$ and is bijective, so
  $\kappa(x) \cong \bar k$.
\end{proof}
